,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT sc.concat_segments,',
'       sc.segment1, sc.segment2, sc.segment3, sc.segment4, sc.segment5, sc.segment6',
'FROM DMT_LOOKUP.DMT_COA_SOURCE_COMBOS sc',
'JOIN DMT_LOOKUP.DMT_COA_MAP_CONFIG mc ON mc.source_coa_set_id = sc.coa_set_id',
'WHERE mc.config_code = :P34_CONFIG_CODE',
'  AND sc.enabled_flag = ''Y''',
'  AND NOT EXISTS (',
'      SELECT 1 FROM DMT_LOOKUP.DMT_COA_MAPPING m',
'      WHERE m.map_config_id = mc.map_config_id',
'      AND m.source_concat = sc.concat_segments',
'      AND m.active_flag = ''Y''',
'  )',
'ORDER BY sc.concat_segments'))
