,p_attribute_01=>'var btn=document.getElementById("btn-confirm");btn.disabled=true;btn.textContent="Submitting...";var body=new URLSearchParams();body.append("p_flow_id",$v("pFlowId"));body.append("p_flow_step_id",$v("pFlowStepId"));body.append("p_instance",$v("pInstance"));body.append("p_request","APPLICATION_PROCESS=SUBMIT_AJAX");body.append("p_json",JSON.stringify({pageItems:null,salt:null}));body.append("x01",window._planCodes||"");body.append("x02",$v("P84_SCENARIO")||"");body.append("x03",$v("P84_RUN_MODE")||"NEW");body.append("x04","HALT");fetch("wwv_flow.ajax",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded; charset=UTF-8"},body:body.toString()}).then(function(r){return r.text();}).then(function(d){btn.disabled=false;btn.textContent="Confirm & Submit";d=(d||"").trim();if(d.indexOf("OK:")===0){var rid=d.substring(3).trim();var url="f?p="+$v("pFlowId")+":82:"+$v("pInstance")+"::NO::P82_RUN_ID:"+rid;document.getElementById("plan-content").innerHTML="<div style=\"text-align:center;padding:16px\"><p style=\"font-size:17px;color:#1a7d33;margin:0 0 12px\"><b>&#10003; Pipeline submitted as Run #"+rid+"</b></p><a href=\""+url+"\" style=\"display:inline-block;padding:11px 22px;color:#fff;text-decoration:none;border-radius:6px;background:#0072c6;font-weight:600\">Open Run #"+rid+" &rarr; tiles view</a></div>";document.getElementById("btn-confirm").style.display="none";document.getElementById("btn-cancel").textContent="Close";apex.message.showPageSuccess("Pipeline submitted as Run #"+rid);}else{apex.message.alert(d||"Submit returned no response");}}).catch(function(e){btn.disabled=false;btn.textContent="Confirm & Submit";apex.message.alert("Failed: "+e);});'
